      o_wr_data       <=  32'b0;
      r_count         <=  24'b0;
    end
    else begin
      o_wr_stb        <= 0;
      if (i_enable) begin
        if ((i_wr_rdy > 0) && (o_wr_act == 2'b00))begin
          r_count     <=  0;
          if (i_wr_rdy[0]) begin
            o_wr_act[0]  <=  1;
          end
          else begin
            o_wr_act[1]  <=  1;
          end
        end
        else if (o_wr_act > 0) begin
          if (r_count < i_wr_size) begin
            r_count   <=  r_count + 1;
            o_wr_stb  <=  1;
            o_wr_data <=  r_count;
          end
          else begin
            o_wr_act  <=  2'b00;
          end
        end
      end
    end
  end

endmodule

