module autovcoder_071470 (
    a,
    b,
    y
);

  input [12:0] a;
  input [12:0] b;

  output [24:0] y;


  wire [ 6:0] a_mod_1;  //7
  wire [ 6:0] b_mod_1;  //7
  wire [12:0] y_mod_1;  //13

  wire [ 6:0] a_mod_2;  //7
  wire [ 6:0] b_mod_2;  //7
  wire [12:0] y_mod_2;  //13

  wire [ 6:0] a_mod_3;  //7
  wire [ 6:0] b_mod_3;  //7
  wire [12:0] y_mod_3;  //13

  wire [12:0] B1_out1, B1_out2, B1_out3;

  wire [26:0] y_modify;

  KA_7bit bit_mod_1 (
      .y(y_mod_1),
      .a(a_mod_1),
      .b(b_mod_1)
  );
  KA_7bit bit_mod_2 (
      .y(y_mod_2),
      .a(a_mod_2),
      .b(b_mod_2)
  );
  KA_7bit bit_mod_3 (
      .y(y_mod_3),
      .a(a_mod_3),
      .b(b_mod_3)
  );


  assign a_mod_1 = a[6:0], b_mod_1 = b[6:0];

  assign a_mod_2 = {1'b0, a[12:7]}, b_mod_2 = {1'b0, b[12:7]};

  assign a_mod_3 = a[6:0] ^ {1'b0, a[12:7]}, b_mod_3 = b[6:0] ^ {1'b0, b[12:7]};



  assign B1_out1 = y_mod_1;

  assign B1_out2 = y_mod_1 ^ y_mod_2 ^ y_mod_3;

  assign B1_out3 = y_mod_2;


  overlap_module_13bit ov_mod (
      .B2_in1(B1_out1),
      .B2_in2(B1_out2),
      .B2_in3(B1_out3),
      .B2_out(y_modify)
  );

  assign y = y_modify[24:0];

endmodule

