  always @(posedge clk)
  begin
    if (reset)
      current_state <= IDLE;
    else
      current_state <= next_state;
  end

  always @(inp_bit or current_state)
  begin
    case (current_state)
      IDLE:
        if (inp_bit)
          next_state = SEQ_1;
        else
          next_state = IDLE;
      SEQ_1:
        if (inp_bit)
          next_state = SEQ_1;
        else
          next_state = SEQ_10;
      SEQ_10:
        if (inp_bit)
          next_state = SEQ_101;
        else
          next_state = IDLE;
      SEQ_101:
        if (inp_bit)
          next_state = SEQ_1011;
        else
          next_state = SEQ_10;
      SEQ_1011:
        if (inp_bit)
          next_state = SEQ_1;
        else
          next_state = IDLE;
      default:
        next_state = IDLE;
    endcase
  end
endmodule

