module rtlpp_05163 (
    address,
    byteenable,
    chipselect,
    clk,
    clken,
    freeze,
    reset,
    reset_req,
    write,
    writedata,
    readdata
);

parameter INIT_FILE = "lab9_soc_ocm.hex";

output reg [31:0] readdata;
input  [ 9:0] address;
input  [ 3:0] byteenable;
input         chipselect;
input         clk;
input         clken;
input         freeze;
input         reset;
input         reset_req;
input         write;
input  [31:0] writedata;

reg [31:0] memory [0:1023]; // Memory array
wire       clocken0;
wire       wren;
integer i;

// Initialization of memory with INIT_FILE
initial begin
    if (INIT_FILE != "") begin
        $readmemh(INIT_FILE, memory);
    end else begin
        for (i = 0; i < 1024; i = i + 1) begin
            memory[i] = 32'd0;
        end
    end
end

assign wren = chipselect & write;
assign clocken0 = clken & ~reset_req;

always @(posedge clk) begin
    if (clocken0) begin
        if (wren) begin
            if (byteenable[0]) memory[address][ 7: 0] <= writedata[ 7: 0];
            if (byteenable[1]) memory[address][15: 8] <= writedata[15: 8];
            if (byteenable[2]) memory[address][23:16] <= writedata[23:16];
            if (byteenable[3]) memory[address][31:24] <= writedata[31:24];
        end
        readdata <= memory[address];
    end
end

endmodule

