  wsi1_MByteEn = wsi0_MByteEn; 
  wsi1_MReqInfo = wsi0_MReqInfo; 
  wci_SThreadBusy = 1'b0; 
  wci_SResp = 2'b0; 
  if (rst_n==1'b0) begin 
  wci_ctlSt = 3'h0; 
  wci_SResp = 2'h0; 
  wci_SFlag = 2'h0; 
  wci_SThreadBusy = 2'b1; 
  biasValue = 32'h0000_0000; 
  end else begin 
  if (wci_cfg_write==1'b1) begin 
  biasValue = wci_MData; 
  wci_SResp = 2'h1; 
  end 
  if (wci_cfg_read==1'b1) begin 
  wci_SData = biasValue; 
  wci_SResp = 2'h1; 
  end 
  if (wci_ctl_op==1'b1) begin 
  case (wci_MAddr[4:2]) 
  2'h0 : wci_ctlSt = 3'h1; 
  2'h1 : wci_ctlSt = 3'h2; 
  2'h2 : wci_ctlSt = 3'h3; 
  2'h3 : wci_ctlSt = 3'h0; 
  endcase 
  wci_SData = 32'hC0DE_4201; 
  wci_SResp = 2'h1; 
