module mg_03568(clk,rst_n,in_enable,in_data,out_ready,out_data,count_x,count_y);
parameter work_mode = 0; 
  parameter data_width = 8; 
  parameter im_width = 320; 
  parameter im_height = 240; 
  parameter im_width_bits = 9; 
  input clk; 
  input rst_n; 
  input in_enable; 
  input [data_width - 1 : 0] in_data; 
  output out_ready; 
  output[data_width - 1 : 0] out_data; 
  output reg[im_width_bits - 1 : 0] count_x; 
  output reg[im_width_bits - 1 : 0] count_y; 
  assign out_ready = in_enable; 
  assign out_data = out_ready ? in_data : 0; 
  generate 
  if(work_mode == 0) begin 
  always @(posedge clk or negedge rst_n or negedge in_enable) begin 
  if(~rst_n || ~in_enable) 
  count_x <= 0; 
  else if(count_x == im_width - 1) 
  count_x <= 0; 
  else 
  count_x <= count_x + 1; 
  end 
  always @(posedge clk or negedge rst_n or negedge in_enable) begin 
  if(~rst_n || ~in_enable) 
  count_y <= 0; 
  else if(count_x == im_width - 1 && count_y == im_height - 1) 
  count_y <= 0; 
  else if(count_x == im_width - 1) 
  count_y <= count_y + 1; 
  else 
  count_y <= count_y; 
  end 
  end else begin 
  always @(posedge in_enable or negedge rst_n) begin 
  if(~rst_n) 
  count_x <= 0; 
  else if(count_x == im_width - 1) 
  count_x <= 0; 
  else 
  count_x <= count_x + 1; 
  end 
  always @(posedge in_enable or negedge rst_n) begin 
  if(~rst_n) 
  count_y <= 0; 
  else if(count_x == im_width - 1 && count_y == im_height - 1) 
  count_y <= 0; 
  else if(count_x == im_width - 1) 
  count_y <= count_y + 1; 
  else 
  count_y <= count_y; 
  end 
  end 
  endgenerate 
 endmodule

