  ORI = 6'b001101, 
  XORI = 6'b001110, 
  SLTI = 6'b001010; 
  reg memory_op; 
  reg r_type_op; 
  reg immediate_op; 
  reg branch_op; 
  reg jump_op; 
  assign ex_imm_command = immediate_op; 
  assign id_rt_is_source = (r_type_op | branch_op | opcode == SW); 
