  ex_dst_reg_sel = 1'b0; 
  ex_alu_op = 2'b10; 
  wb_mem_to_reg = 1'b0; 
  wb_reg_write = 1'b1; 
  end 
  else if (branch_op) begin 
  if (branch_eq) 
  if_pc_source = 2'b01; 
