module autovcoder_119451 #(
    parameter ID         = 0,
              NUM_STAGE  = 1,
              din0_WIDTH = 32,
              din1_WIDTH = 32,
              din2_WIDTH = 32,
              din3_WIDTH = 32,
              din4_WIDTH = 32,
              din5_WIDTH = 32,
              din6_WIDTH = 32,
