              dout_WIDTH = 32
) (
    input  [15 : 0] din0,
    input  [15 : 0] din1,
    input  [15 : 0] din2,
    input  [15 : 0] din3,
    input  [15 : 0] din4,
    input  [15 : 0] din5,
    input  [15 : 0] din6,
    input  [15 : 0] din7,
    input  [15 : 0] din8,
    output [15 : 0] dout
);

  // puts internal signals
  wire [15 : 0] sel;
  // level 1 signals
  wire [15 : 0] mux_1_0;
  wire [15 : 0] mux_1_1;
  wire [15 : 0] mux_1_2;
  wire [15 : 0] mux_1_3;
  // level 2 signals
  wire [15 : 0] mux_2_0;
  wire [15 : 0] mux_2_1;
  // level 3 signals
  wire [15 : 0] mux_3_0;
  // level 4 signals
  wire [15 : 0] mux_4_0;
  // level 5 signals
  wire [15 : 0] mux_5_0;
  // level 6 signals
  wire [15 : 0] mux_6_0;
  // level 7 signals
  wire [15 : 0] mux_7_0;
  // level 8 signals
  wire [15 : 0] mux_8_0;
  // level 9 signals
  wire [15 : 0] mux_9_0;
  // level 10 signals
