files.autovcoder_095752.v:
module autovcoder_095752 (
    input clk_74a,
    input clk_sys,
    input reset_l,

    input bigendin,

    // Ram Controller
    output reg        word_rd,
    output reg        word_wr,
    output reg [25:0] word_addr,
    output reg [31:0] word_data,
    input      [31:0] word_q,
    input             word_busy,

    // SPI interface
    input      [31:0] bridge_addr,
    input             bridge_rd,
    output reg [31:0] bridge_rd_data,
    input             bridge_wr,
    input      [31:0] bridge_wr_data,
    output reg        bridge_processing,
    output reg        bridge_completed
);



  /*************************************************************

	interface controller to Memory cores once the dataslot
	is confirmed.

*************************************************************/

  reg [1:0]  RAM_STATE;

  reg    requested_read;

  parameter idle = 'd0;
  parameter request = 'd1;
  parameter wait_read = 'd2;


  wire bridge_rd_s, bridge_rd_r, bridge_rd_f;
  synch_3 s00 (
      bridge_rd,
      bridge_rd_s,
      clk_sys,
      bridge_rd_r,
      bridge_rd_f
  );

  wire bridge_wr_s, bridge_wr_r, bridge_wr_f;
  synch_3 s01 (
      bridge_wr,
      bridge_wr_s,
      clk_sys,
      bridge_wr_r,
      bridge_wr_f
  );

  wire [31:0] bridge_wr_data_s;
  synch_3 #(
      .WIDTH(32)
  ) s02 (
      bridge_wr_data,
      bridge_wr_data_s,
      clk_sys
  );

  wire [31:0] bridge_addr_s;
  synch_3 #(
      .WIDTH(32)
  ) s03 (
      bridge_addr,
      bridge_addr_s,
      clk_sys
  );

  always @(posedge clk_sys or negedge reset_l) begin
    if (~reset_l) begin
      RAM_STATE         <= 'd0;
      requested_read    <= 'd0;
      word_rd           <= 'd0;
      word_wr           <= 'd0;
      word_addr         <= 'd0;
      word_data         <= 'd0;
      bridge_rd_data    <= 'd0;
      bridge_completed  <= 'b0;
      bridge_processing <= 'b0;
    end else begin
      word_rd          <= 'd0;
      word_wr          <= 'd0;
      bridge_completed <= 'b0;
      case (RAM_STATE)
        request: begin
          word_wr           <= 'b0;
          word_rd           <= 'b0;
          bridge_processing <= 'b1;
          if (~word_busy) begin  // we need to wait for access
            word_addr 					<= bridge_addr_s[25:0]; // We have to make sure that we are doing a 32bit word process here
            if (requested_read) begin
              RAM_STATE <= wait_read;
              word_rd   <= 'b1;
            end else begin
              RAM_STATE <= idle;
              word_wr <= 'b1;
              bridge_processing <= 'b0;
              word_data 					<= bigendin ? bridge_wr_data_s : 
														{bridge_wr_data_s[23:16], bridge_wr_data_s[31:24], bridge_wr_data_s[7:0], bridge_wr_data_s[15:8]};
            end
          end
        end
        wait_read: begin
          if (~word_busy) begin
            RAM_STATE        <= idle;
            bridge_completed <= 'b1;
            case (bigendin)
              1'b1   : bridge_rd_data <= word_q;
              default  : bridge_rd_data <= {word_q[23:16], word_q[31:24], word_q[7:0], word_q[15:8]};
            endcase
            bridge_processing <= 'b0;
          end
        end
        default: begin
          if (bridge_rd_f || bridge_wr_f) begin
            RAM_STATE         <= request;
            requested_read    <= bridge_rd_f;
            bridge_processing <= 'b1;
          end else begin
            RAM_STATE      <= 'd0;
            requested_read <= 'd0;
            word_rd        <= 'd0;
            word_wr        <= 'd0;
          end
        end
      endcase
    end
  end


endmodule

