    if (s_axi_rready & s_axi_rvalid) begin
      s_axi_rvalid <= 0;
    end else if (s_axi_arvalid & s_axi_arready) begin
      s_axi_rid <= s_axi_arid;
      s_axi_rdata <= 32'hDEADBEEF; // Example read data
      s_axi_rresp <= 2'b00; // OKAY response
      s_axi_rlast <= 1;
      s_axi_rvalid <= 1;
    end

