assign clk_recovered = S_clk_recovered;
assign clk_recovered_edge = (R_clk_recovered_shift[1] != S_clk_recovered) ? 1'b1 : 1'b0;
assign S_linebit = R_dif_shift[0];
assign S_bit = ~(S_linebit ^ R_linebit_prev);

