files.autovcoder_059129.v:
module autovcoder_059129 (
    input  wire        clk,
    input  wire        rst,
    // Incoming port
    input  wire [21:0] a_data,
    input  wire        a_valid,
    output wire        a_ready,
    // Outgoing port
    input  wire        b_short,
    output wire [63:0] b_data,
    output wire        b_valid,
    input  wire        b_ready
);
  // Store from higher order byte to lower order
  reg [63:0] fifo;
  reg [1:0] fifo_level;
  wire fifo_full = (b_short) ? (fifo_level == 2) : (fifo_level == 3);

  wire [63:0] new_data =
            ((fifo_level == 2) && !b_short) ? {fifo[63:22], a_data} :
            (fifo_level == 1) ? {fifo[63:44], a_data, 22'b0} :
            ((fifo_level == 0) || ((fifo_level == 3) || (b_short && (fifo_level == 2)))) ? {a_data[19:0], 44'b0} :
            64'bx;

  always @(posedge clk) begin
    if (fifo_full) begin
      if (b_ready && a_valid) begin
        // Output ready, input valid, shiftin new data
        fifo <= new_data;
        fifo_level <= 1;
      end else if (b_ready) begin
        // Output ready, no input, output data
        fifo_level <= 0;
      end
    end else begin
      // Not full, output not valid, input ready
      if (a_valid) begin
        fifo <= new_data;
        fifo_level <= fifo_level + 1;
      end
    end

    if (rst) begin
      fifo_level <= 0;
    end
  end

  // RX data if fifo is empty
  assign a_ready = !fifo_full || (fifo_full && b_ready);
  assign b_valid = fifo_full;
  assign b_data  = fifo;

endmodule

files.origen_098224.v:
module origen_098224 (
    input wire clk,
    input wire rst_n,
    input wire wrt,
    input wire [10:0] SPEED,
    output reg PWM
);

    reg [10:0] SPEED_ff;
    reg wrt_ff;
    reg [13:0] q1;
    wire [13:0] num_ticks;
    wire Set, Rst;

    // Input synchronization
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            SPEED_ff <= 11'b0;
            wrt_ff <= 1'b0;
        end else begin
            SPEED_ff <= SPEED;
            wrt_ff <= wrt;
        end
    end

    // PWM period calculation
    assign num_ticks = {3'b0, SPEED_ff} * 3 + 14'h186A;

    // Down counter
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            q1 <= 14'b0;
        end else if (wrt_ff) begin
            q1 <= num_ticks;
        end else if (q1 != 14'b0) begin
            q1 <= q1 - 1'b1;
        end
    end

    // Set and Reset signals
    assign Set = wrt_ff;
    assign Rst = (q1 == 14'b0);

    // PWM output generation
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            PWM <= 1'b0;
        end else if (Set) begin
            PWM <= 1'b1;
        end else if (Rst) begin
            PWM <= 1'b0;
        end
    end

endmodule

files.origen_187000.v:
module origen_187000 (
    input clk,
    input reset,
    input [1:0] time_parameter_selector,
    input [3:0] time_value,
    input prog_sync,
    input [1:0] interval_code,
    output reg [3:0] value
);

reg [3:0] time_base, time_yel, time_ext;
reg [3:0] temp_base, temp_yel, temp_ext;

initial begin
    time_base = 4'b0110;
    time_yel = 4'b0010;
    time_ext = 4'b0011;
end

always @(posedge clk or posedge reset) begin
    if (reset) begin
        time_base <= 4'b0110;
        time_yel <= 4'b0010;
        time_ext <= 4'b0011;
    end
    else begin
        if (prog_sync) begin
            time_base <= temp_base;
            time_yel <= temp_yel;
            time_ext <= temp_ext;
        end
        else begin
            case (time_parameter_selector)
                2'b00: temp_base <= time_value;
                2'b01: temp_yel <= time_value;
                2'b10: temp_ext <= time_value;
                default: ;
            endcase
        end
    end
end

always @(*) begin
    case (interval_code)
        2'b00: value = time_base;
        2'b01: value = time_yel;
        2'b10: value = time_ext;
        2'b11: value = time_base + time_ext;
        default: value = 4'b0000;
    endcase
end

endmodule

files.origen_106471.v:
module origen_106471(
    input wire clock,
    input wire reset,
    input wire crash,
    input wire press,
    output reg [7:0][7:0] green
);

    reg [2:0] count;
    reg [7:0] counter;
    reg on;

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            count <= 3'b100;
            counter <= 8'b0;
            on <= 1'b0;
        end else if (crash) begin
            count <= 3'bx;
        end else begin
            if (counter == 8'b10000000) begin
                counter <= 8'b0;
                on <= 1'b1;
            end else begin
                counter <= counter + 1'b1;
                on <= 1'b0;
            end

            if (press)
                count <= count + 1'b1;
            else if (on)
                count <= count - 1'b1;
        end
    end

    always @* begin
        green = 64'b0;
        if (!crash) begin
            case (count)
                3'b000: green[2][7] = 1'b1;
                3'b001: green[2][6] = 1'b1;
                3'b010: green[2][5] = 1'b1;
                3'b011: green[2][4] = 1'b1;
                3'b100: green[2][3] = 1'b1;
                3'b101: green[2][2] = 1'b1;
                3'b110: green[2][1] = 1'b1;
                3'b111: green[2][0] = 1'b1;
                default: green = 64'b0;
            endcase
        end
    end

endmodule

files.origen_172499.v:
module origen_172499(
    input HCLK,
    input HRESETn,
    input HSEL,
    input [31:0] HADDR,
    input [1:0] HTRANS,
    input [2:0] HSIZE,
    input [3:0] HPROT,
    input HWRITE,
    input [31:0] HWDATA,
    input HREADY,
    input [7:0] UART_RX,
    input [0:0] state,

    output reg HREADYOUT,
    output reg [31:0] HRDATA,
    output HRESP,
    output reg tx_en,
    output reg [7:0] UART_TX
);

    reg [3:0] addr_reg;

    wire read_en = HSEL && (HTRANS == 2'b10) && !HWRITE && HREADY;
    wire write_en = HSEL && (HTRANS == 2'b10) && HWRITE && HREADY;

    always @(posedge HCLK or negedge HRESETn) begin
        if (!HRESETn) begin
            addr_reg <= 4'b0;
            tx_en <= 1'b0;
            UART_TX <= 8'b0;
            HREADYOUT <= 1'b1;
            HRDATA <= 32'b0;
        end else begin
            if (read_en) begin
                addr_reg <= HADDR[3:0];
                if (addr_reg == 4'b0000) begin
                    HRDATA <= {24'b0, UART_RX};
                end else if (addr_reg == 4'b0100) begin
                    HRDATA <= {31'b0, state};
                end else begin
                    HRDATA <= 32'b0;
                end
            end else if (write_en) begin
                addr_reg <= HADDR[3:0];
                tx_en <= 1'b1;
                UART_TX <= HWDATA[7:0];
            end
        end
    end

    assign HRESP = 1'b0;

endmodule

