module origen_165828(
    input clk,
    input reset,
    output reg [3:0] an,
    output reg [6:0] sseg
);

reg [18:0] ms_count;
reg [8:0] displayed_number;
reg [20:0] refresh_count;
reg [1:0] LED_activating_counter;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        ms_count <= 0;
        displayed_number <= 0;
        refresh_count <= 0;
        LED_activating_counter <= 0;
    end
    else begin
