module Positive_Time (
    input wire sig,
    input wire clk,
    output reg [31:0] p_time
);
    reg [31:0] tmp;

    always @(posedge clk or negedge sig) begin
        if (~sig) begin
            p_time <= tmp;
            tmp <= 32'd0;
        end else if (sig) begin
            tmp <= tmp + 1;
        end
    end
endmodule

module getPeriod (
    input wire sig,
    input wire clk,
    output reg [31:0] period
);
    reg count_en;
    reg [31:0] tmp;

    always @(posedge sig) begin
        count_en <= ~count_en;
    end

    always @(posedge clk or negedge count_en) begin
        if (~count_en) begin
            period <= tmp;
            tmp <= 32'd0;
        end else if (count_en) begin
            tmp <= tmp + 1;
        end
    end
endmodule

